body.script:
test(function() {
  assert_background_color('t1', LIME);
  assert_background_color('t2', LIME);
  assert_background_color('t3', LIME);
  assert_not_background_color('t4', LIME);
  assert_not_background_color('t4', RED);
  assert_not_background_color('t5', LIME);
  assert_not_background_color('t5', RED);
  assert_not_background_color('t6', LIME);
  assert_not_background_color('t6', RED);
}, 'NEGATED Attribute space-separated value selector with universal namespace');
